#include <bits/stdc++.h>
using namespace std;
int n,f,a[2003],dp[2003][1000];
int main(){
    cin>>n>>f;
    for(int i=1;i<=n;i++)
        cin>>a[i];
    for(int i=1;i<=n;i++)
        for(int j=0;j<f;j++)
            dp[i][j]=(a[i]%f==j)+dp[i-1][j]+dp[i-1][j+(a[i]%f>j)*f-(a[i]%f)],dp[i][j]%=100000000;
        cout<<dp[n][0];
    return 0;
}
